settings.custom_liquid:
{%- comment -%}
Premium "Best Results Tips" card
Edit title + tips below.
{%- endcomment -%}

{%- assign title = 'Best Results Tips' -%}
{%- assign kicker = 'Recommended routine' -%}
{%- assign tips = 'Use 2-3x per week, on clean/dry scalp|Always start with the lowest setting|Pair with your favorite growth serum or oil|Take before photos to track your progress!' -%}

{%- style -%}
  .nuve-tips-wrap{
    --ink: #0f172a;
    --muted: rgba(15, 23, 42, 0.72);
    --brand: #557170;
    --cream: #F1EFE7;
    --lilac: #C9B7FF;

    border-radius: 18px;
    padding: 22px 22px;
    background:
      radial-gradient(900px 260px at 15% 0%, rgba(201, 183, 255, 0.20), transparent 55%),
      radial-gradient(900px 260px at 85% 100%, rgba(85, 113, 112, 0.16), transparent 55%),
      linear-gradient(180deg, #ffffff, var(--cream));
    border: 1px solid rgba(15, 23, 42, 0.08);
    box-shadow: 0 14px 40px rgba(15, 23, 42, 0.08);
    overflow: hidden;
  }

  .nuve-tips-header{
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
  }

  .nuve-tips-icon{
    width: 42px;
    height: 42px;
    border-radius: 14px;
    background: rgba(85, 113, 112, 0.10);
    border: 1px solid rgba(85, 113, 112, 0.18);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
  }
  .nuve-tips-icon svg{
    width: 22px;
    height: 22px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tips-kicker{
    display: inline-flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    font-weight: 700;
    color: var(--brand);
    margin-bottom: 6px;
  }
  .nuve-tips-pill{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 10px;
    border-radius: 9999px;
    background: rgba(201, 183, 255, 0.18);
    border: 1px solid rgba(201, 183, 255, 0.35);
    color: var(--ink);
    font-size: 11px;
    font-weight: 700;
    line-height: 1;
  }

  .nuve-tips-title{
    font-size: 22px;
    font-weight: 800;
    color: var(--ink);
    line-height: 1.15;
    margin: 0;
  }

  .nuve-tips-grid{
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    margin-top: 14px;
  }

  .nuve-tip{
    display: grid;
    grid-template-columns: 26px 1fr;
    gap: 12px;
    align-items: flex-start;
    padding: 12px 12px;
    border-radius: 14px;
    background: rgba(255, 255, 255, 0.62);
    border: 1px solid rgba(15, 23, 42, 0.06);
    transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease;
  }

  .nuve-tip:hover{
    transform: translateY(-1px);
    box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);
    background: rgba(255, 255, 255, 0.78);
  }

  .nuve-check{
    width: 22px;
    height: 22px;
    border-radius: 9999px;
    background: rgba(85, 113, 112, 0.12);
    border: 1px solid rgba(85, 113, 112, 0.20);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 2px;
  }
  .nuve-check svg{
    width: 14px;
    height: 14px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2.5;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tip-text{
    font-size: 14px;
    font-weight: 600;
    color: var(--ink);
    line-height: 1.35;
  }

  /* Optional: 2-column on larger screens */
  @media (min-width: 750px){
    .nuve-tips-wrap{ padding: 26px 26px; }
    .nuve-tips-grid{ grid-template-columns: 1fr 1fr; }
    .nuve-tips-title{ font-size: 24px; }
  }
{%- endstyle -%}

<div class="nuve-tips-wrap">
  <div class="nuve-tips-header">
    <div class="nuve-tips-icon" aria-hidden="true">
      <!-- sparkle/idea icon -->
      <svg viewBox="0 0 24 24">
        <path d="M12 2l1.2 3.8L17 7l-3.8 1.2L12 12l-1.2-3.8L7 7l3.8-1.2L12 2z"/>
        <path d="M5 13l.8 2.6L8 16l-2.2.7L5 19l-.8-2.3L2 16l2.2-.4L5 13z"/>
        <path d="M18 13l.8 2.6L21 16l-2.2.7L18 19l-.8-2.3L15 16l2.2-.4L18 13z"/>
      </svg>
    </div>

    <div>
      <div class="nuve-tips-kicker">
        <span class="nuve-tips-pill">{{ kicker }}</span>
      </div>
      <h3 class="nuve-tips-title">{{ title }}</h3>
    </div>
  </div>

  <div class="nuve-tips-grid" role="list">
    {%- assign tip_items = tips | split: '|' -%}
    {%- for t in tip_items -%}
      <div class="nuve-tip" role="listitem">
        <span class="nuve-check" aria-hidden="true">
          <svg viewBox="0 0 24 24">
            <path d="M20 6L9 17l-5-5"/>
          </svg>
        </span>
        <div class="nuve-tip-text">{{ t }}</div>
      </div>
    {%- endfor -%}
  </div>
</div>

{%- comment -%}
Premium "Safety & Comfort" section (Custom Liquid)
Edit the content variables below.
{%- endcomment -%}

{%- assign heading = 'Safety & Comfort' -%}
{%- assign subheading = 'Designed to feel gentle, hygienic, and easy to use - even for sensitive scalps.' -%}

{%- assign bullets = 'FDA-cleared materials|Painless for most users (gentle vibration)|Safe for all hair types and scalp sensitivities|Full instructions and support included' -%}

{%- assign cta_title = 'Ready to try it?' -%}
{%- assign cta_subtitle = 'Still have questions?' -%}

{%- assign primary_label = 'Buy Nuvé Stamp' -%}
{%- assign primary_link = '/products/nuve-stamp' -%}

{%- assign secondary_label = 'Read the FAQs' -%}
{%- assign secondary_link = '/pages/faq' -%}

{%- style -%}
  .nuve-sc-wrap{
    --ink: #0f172a;
    --muted: rgba(15, 23, 42, 0.70);
    --brand: #557170;
    --cream: #F1EFE7;
    --lilac: #C9B7FF;

    max-width: 980px;
    margin: 0 auto;
    padding: 34px 18px;
  }

  .nuve-sc-card{
    border-radius: 22px;
    background:
      radial-gradient(900px 320px at 15% 0%, rgba(201, 183, 255, 0.22), transparent 55%),
      radial-gradient(900px 320px at 85% 100%, rgba(85, 113, 112, 0.14), transparent 55%),
      linear-gradient(180deg, #fff, var(--cream));
    border: 1px solid rgba(15, 23, 42, 0.08);
    box-shadow: 0 18px 55px rgba(15, 23, 42, 0.10);
    padding: 26px;
  }

  .nuve-sc-head{
    text-align: center;
    margin-bottom: 18px;
  }

  .nuve-sc-title{
    font-size: 30px;
    font-weight: 900;
    letter-spacing: -0.02em;
    color: var(--ink);
    margin: 0;
    line-height: 1.15;
  }

  .nuve-sc-accent{
    width: 78px;
    height: 4px;
    border-radius: 9999px;
    margin: 10px auto 0;
    background: linear-gradient(90deg, rgba(201, 183, 255, 0.0), rgba(201, 183, 255, 0.85), rgba(201, 183, 255, 0.0));
  }

  .nuve-sc-sub{
    margin: 10px auto 0;
    max-width: 680px;
    font-size: 14px;
    font-weight: 600;
    color: var(--muted);
    line-height: 1.45;
  }

  .nuve-sc-grid{
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    margin-top: 18px;
  }

  .nuve-sc-item{
    display: grid;
    grid-template-columns: 44px 1fr;
    gap: 12px;
    align-items: start;
    padding: 14px 14px;
    border-radius: 16px;
    background: rgba(255, 255, 255, 0.68);
    border: 1px solid rgba(15, 23, 42, 0.06);
    transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease;
  }

  .nuve-sc-item:hover{
    transform: translateY(-1px);
    box-shadow: 0 10px 26px rgba(15, 23, 42, 0.08);
    background: rgba(255, 255, 255, 0.82);
  }

  .nuve-sc-ico{
    width: 38px;
    height: 38px;
    border-radius: 9999px;
    background: rgba(201, 183, 255, 0.22);
    border: 1px solid rgba(201, 183, 255, 0.35);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 1px;
  }

  .nuve-sc-ico svg{
    width: 18px;
    height: 18px;
    stroke: var(--ink);
    stroke-width: 2.5;
    fill: none;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-sc-text{
    font-size: 14px;
    font-weight: 700;
    color: var(--ink);
    line-height: 1.35;
  }

  .nuve-sc-cta{
    margin-top: 18px;
    border-radius: 18px;
    background: rgba(255, 255, 255, 0.65);
    border: 1px solid rgba(15, 23, 42, 0.06);
    padding: 18px;
    display: grid;
    gap: 12px;
    text-align: center;
  }

  .nuve-sc-cta-title{
    font-size: 15px;
    font-weight: 900;
    color: var(--ink);
    margin: 0;
  }

  .nuve-sc-cta-sub{
    font-size: 13px;
    font-weight: 600;
    color: var(--muted);
    margin: -6px 0 0;
  }

  .nuve-sc-actions{
    display: flex;
    gap: 10px;
    justify-content: center;
    flex-wrap: wrap;
    margin-top: 4px;
  }

  .nuve-btn{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 12px 16px;
    border-radius: 9999px;
    font-size: 13px;
    font-weight: 800;
    text-decoration: none;
    line-height: 1;
    transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease, border-color 140ms ease;
  }

  .nuve-btn--primary{
    background: #111;
    color: #fff;
    box-shadow: 0 10px 25px rgba(0,0,0,0.18);
  }
  .nuve-btn--primary:hover{
    transform: translateY(-1px);
    box-shadow: 0 14px 32px rgba(0,0,0,0.22);
  }

  .nuve-btn--secondary{
    background: rgba(201, 183, 255, 0.18);
    border: 1px solid rgba(201, 183, 255, 0.40);
    color: var(--ink);
  }
  .nuve-btn--secondary:hover{
    transform: translateY(-1px);
    box-shadow: 0 12px 26px rgba(15, 23, 42, 0.10);
  }

  /* Desktop: 2 columns for bullets, CTA stays centered */
  @media (min-width: 750px){
    .nuve-sc-wrap{ padding: 46px 18px; }
    .nuve-sc-card{ padding: 30px; }
    .nuve-sc-grid{ grid-template-columns: 1fr 1fr; }
    .nuve-sc-title{ font-size: 34px; }
  }
{%- endstyle -%}

<section class="nuve-sc-wrap">
  <div class="nuve-sc-card">
    <div class="nuve-sc-head">
      <h2 class="nuve-sc-title">{{ heading }}</h2>
      <div class="nuve-sc-accent" aria-hidden="true"></div>
      <div class="nuve-sc-sub">{{ subheading }}</div>
    </div>

    <div class="nuve-sc-grid" role="list">
      {%- assign items = bullets | split: '|' -%}
      {%- for item in items -%}
        <div class="nuve-sc-item" role="listitem">
          <span class="nuve-sc-ico" aria-hidden="true">
            <!-- check in circle -->
            <svg viewBox="0 0 24 24">
              <path d="M20 6L9 17l-5-5"></path>
            </svg>
          </span>
          <div class="nuve-sc-text">{{ item }}</div>
        </div>
      {%- endfor -%}
    </div>

    <div class="nuve-sc-cta">
      <p class="nuve-sc-cta-title">{{ cta_title }}</p>
      <p class="nuve-sc-cta-sub">{{ cta_subtitle }}</p>

      <div class="nuve-sc-actions">
        <a class="nuve-btn nuve-btn--primary" href="{{ primary_link }}">{{ primary_label }}</a>
        <a class="nuve-btn nuve-btn--secondary" href="{{ secondary_link }}">{{ secondary_label }}</a>
      </div>
    </div>
  </div>
</section>
